"""Gestion du budget tokens et coÃ»t pour Hermes SEO.

ArrÃªt BLOQUANT (pas skip automatique silencieux) si les seuils sont dÃ©passÃ©s.
"""

from dataclasses import dataclass, field


@dataclass
class BudgetTracker:
    """Suivi du budget d'une session."""

    token_budget: int
    cost_budget: float
    tokens_used: int = 0
    cost_used: float = 0.0
    warnings: list[str] = field(default_factory=list)

    # CoÃ»ts par million de tokens (entrÃ©e, sortie)
    MODEL_COSTS: dict = field(default_factory=lambda: {
        "claude-sonnet-4-6": (3.00, 15.00),
        "claude-haiku-4-5": (1.00, 5.00),
        "claude-opus-4-7": (5.00, 25.00),
        "gpt-5.4": (2.50, 15.00),
        "gpt-5.4-mini": (0.75, 4.50),
        "gpt-5.4-nano": (0.20, 1.25),
        "deepseek-v4-flash": (0.14, 0.28),
        "deepseek-v4-pro": (0.435, 0.87),
    })

    def estimate_cost(self, model: str, tokens_input: int, tokens_output: int) -> float:
        """Estime le coÃ»t d'un appel LLM."""
        costs = self.MODEL_COSTS.get(model, (0, 0))
        input_cost = (tokens_input / 1_000_000) * costs[0]
        output_cost = (tokens_output / 1_000_000) * costs[1]
        return input_cost + output_cost

    def can_proceed(self, estimated_input: int, estimated_output: int, model: str) -> tuple[bool, str]:
        """VÃ©rifie si l'appel peut Ãªtre fait dans le budget.

        Returns (peut_continuer, message).
        """
        estimated_cost = self.estimate_cost(model, estimated_input, estimated_output)
        estimated_total_tokens = self.tokens_used + estimated_input + estimated_output
        estimated_total_cost = self.cost_used + estimated_cost

        if estimated_total_tokens > self.token_budget:
            return False, (
                f"Budget tokens dÃ©passÃ© : {estimated_total_tokens:,} estimÃ©s / "
                f"{self.token_budget:,} autorisÃ©s. CoÃ»t estimÃ©: ${estimated_total_cost:.4f}"
            )

        if estimated_total_cost > self.cost_budget:
            return False, (
                f"Budget coÃ»t dÃ©passÃ© : ${estimated_total_cost:.4f} estimÃ©s / "
                f"${self.cost_budget:.2f} autorisÃ©s."
            )

        if estimated_total_cost > self.cost_budget * 0.8:
            return True, (
                f"Alerte budget : ${estimated_total_cost:.4f} estimÃ©s "
                f"(>80% du budget de ${self.cost_budget:.2f})"
            )

        return True, ""

    def record_usage(self, tokens_input: int, tokens_output: int, model: str) -> None:
        """Enregistre la consommation rÃ©elle."""
        cost = self.estimate_cost(model, tokens_input, tokens_output)
        self.tokens_used += tokens_input + tokens_output
        self.cost_used += cost

    @property
    def remaining_tokens(self) -> int:
        return max(0, self.token_budget - self.tokens_used)

    @property
    def remaining_cost(self) -> float:
        return max(0.0, self.cost_budget - self.cost_used)

    def summary(self) -> str:
        pct_tokens = (self.tokens_used / self.token_budget * 100) if self.token_budget else 0
        pct_cost = (self.cost_used / self.cost_budget * 100) if self.cost_budget else 0
        return (
            f"Budget: {self.tokens_used:,}/{self.token_budget:,} tokens ({pct_tokens:.0f}%), "
            f"${self.cost_used:.4f}/${self.cost_budget:.2f} ({pct_cost:.0f}%)"
        )

# â”€â”€â”€ Helpers pour le sÃ©quencement â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€


def get_agents_for_mode(mode: QualityMode) -> set[str]:
    """Retourne les agents activÃ©s pour un mode qualitÃ© donnÃ©."""
    fast = {
        "agent_00", "agent_01", "agent_04", "agent_07",
        "agent_09", "agent_10", "agent_11", "agent_15", "agent_25",
    }
    standard = fast | {
        "agent_02", "agent_03", "agent_05", "agent_06", "agent_08",
        "agent_12", "agent_13", "agent_16", "agent_21", "agent_22", "agent_23",
    }
    premium = standard | {
        "agent_14", "agent_17", "agent_18", "agent_19",
        "agent_20", "agent_24", "agent_26",
    }
    compliance = premium  # MÃªmes agents, comportement renforcÃ©
    debug = set(AGENT_ORDER)

    mapping = {
        QualityMode.FAST: fast,
        QualityMode.STANDARD: standard,
        QualityMode.PREMIUM: premium,
        QualityMode.COMPLIANCE: compliance,
        QualityMode.DEBUG: debug,
    }
    return mapping.get(mode, standard)

