                    text, ti, to = await self._call_provider(
                        fb_config, system_prompt, user_message, temperature, max_tokens
                    )
                    return text, ti, to, fallback
                except Exception:
                    continue
        raise  # Aucun fallback n'a fonctionnÃ©

